import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { isDirector } from '@/lib/endorsements';
import { getSupabaseAdmin } from '@/lib/supabase';
import { createBulkNotifications } from '@/lib/notifications';

// Helper to get current user
async function getCurrentUser(email: string) {
  const supabase = getSupabaseAdmin();
  const { data } = await supabase
    .from('lab_users')
    .select('id, name, email, role')
    .ilike('email', email)
    .single();
  return data;
}

// GET - Get shift details with signups
export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params;

  try {
    const session = await getServerSession(authOptions);
    if (!session?.user?.email) {
      return NextResponse.json({ success: false, error: 'Unauthorized' }, { status: 401 });
    }

    const currentUser = await getCurrentUser(session.user.email);
    if (!currentUser) {
      return NextResponse.json({ success: false, error: 'User not found' }, { status: 404 });
    }

    const supabase = getSupabaseAdmin();

    const { data: shift, error } = await supabase
      .from('open_shifts')
      .select(`
        *,
        creator:created_by(id, name, email),
        signups:shift_signups(
          id,
          instructor_id,
          signup_start_time,
          signup_end_time,
          is_partial,
          status,
          confirmed_by,
          confirmed_at,
          declined_reason,
          notes,
          created_at,
          instructor:instructor_id(id, name, email),
          confirmer:confirmed_by(id, name)
        )
      `)
      .eq('id', id)
      .single();

    if (error || !shift) {
      return NextResponse.json({ success: false, error: 'Shift not found' }, { status: 404 });
    }

    // Add computed fields
    const signups = shift.signups || [];
    const confirmedSignups = signups.filter((s: { status: string }) => s.status === 'confirmed');
    const userSignup = signups.find((s: { instructor_id: string }) => s.instructor_id === currentUser.id);

    const processedShift = {
      ...shift,
      signup_count: signups.length,
      confirmed_count: confirmedSignups.length,
      user_signup: userSignup || null,
      is_filled: shift.max_instructors ? confirmedSignups.length >= shift.max_instructors : false
    };

    return NextResponse.json({ success: true, shift: processedShift });
  } catch (error) {
    console.error('Error fetching shift:', error);
    return NextResponse.json({ success: false, error: 'Failed to fetch shift' }, { status: 500 });
  }
}

// PUT - Update shift (directors only)
export async function PUT(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params;

  try {
    const session = await getServerSession(authOptions);
    if (!session?.user?.email) {
      return NextResponse.json({ success: false, error: 'Unauthorized' }, { status: 401 });
    }

    const currentUser = await getCurrentUser(session.user.email);
    if (!currentUser) {
      return NextResponse.json({ success: false, error: 'User not found' }, { status: 404 });
    }

    // Check if user is a director or admin
    const userIsDirector = await isDirector(currentUser.id);
    const isAdmin = currentUser.role === 'admin' || currentUser.role === 'superadmin';

    if (!userIsDirector && !isAdmin) {
      return NextResponse.json({ success: false, error: 'Only directors can update shifts' }, { status: 403 });
    }

    const body = await request.json();
    const { title, description, date, start_time, end_time, location, department, min_instructors, max_instructors } = body;

    const supabase = getSupabaseAdmin();

    const updateData: Record<string, unknown> = {};
    if (title !== undefined) updateData.title = title;
    if (description !== undefined) updateData.description = description;
    if (date !== undefined) updateData.date = date;
    if (start_time !== undefined) updateData.start_time = start_time;
    if (end_time !== undefined) updateData.end_time = end_time;
    if (location !== undefined) updateData.location = location;
    if (department !== undefined) updateData.department = department;
    if (min_instructors !== undefined) updateData.min_instructors = min_instructors;
    if (max_instructors !== undefined) updateData.max_instructors = max_instructors;

    const { data: shift, error } = await supabase
      .from('open_shifts')
      .update(updateData)
      .eq('id', id)
      .select(`
        *,
        creator:created_by(id, name, email)
      `)
      .single();

    if (error) throw error;

    // Fire-and-forget: update linked Google Calendar events if date/time changed
    if (updateData.date || updateData.start_time || updateData.end_time || updateData.title) {
      try {
        const { getEventMappingsByShift, getAccessTokenForUser, updateGoogleEvent } = await import('@/lib/google-calendar');
        const mappings = await getEventMappingsByShift(id);
        for (const mapping of mappings) {
          try {
            const accessToken = await getAccessTokenForUser(mapping.user_email);
            if (!accessToken) continue;
            const patchParams: Record<string, unknown> = {};
            if (updateData.title) patchParams.summary = `PMI Shift: ${updateData.title}`;
            if (updateData.date || updateData.start_time || updateData.end_time) {
              const d = (updateData.date || shift?.date) as string;
              const st = (updateData.start_time || shift?.start_time || '08:00') as string;
              const et = (updateData.end_time || shift?.end_time || '17:00') as string;
              patchParams.startDateTime = `${d}T${st}:00`;
              patchParams.endDateTime = `${d}T${et}:00`;
            }
            updateGoogleEvent(accessToken, mapping.google_event_id, patchParams as any).catch(() => {});
          } catch {
            // Per-mapping errors are non-fatal
          }
        }
      } catch {
        // Calendar sync is best-effort
      }
    }

    return NextResponse.json({ success: true, shift });
  } catch (error) {
    console.error('Error updating shift:', error);
    return NextResponse.json({ success: false, error: 'Failed to update shift' }, { status: 500 });
  }
}

// DELETE - Cancel shift (directors only)
export async function DELETE(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params;

  try {
    const session = await getServerSession(authOptions);
    if (!session?.user?.email) {
      return NextResponse.json({ success: false, error: 'Unauthorized' }, { status: 401 });
    }

    const currentUser = await getCurrentUser(session.user.email);
    if (!currentUser) {
      return NextResponse.json({ success: false, error: 'User not found' }, { status: 404 });
    }

    // Check if user is a director or admin
    const userIsDirector = await isDirector(currentUser.id);
    const isAdmin = currentUser.role === 'admin' || currentUser.role === 'superadmin';

    if (!userIsDirector && !isAdmin) {
      return NextResponse.json({ success: false, error: 'Only directors can cancel shifts' }, { status: 403 });
    }

    const supabase = getSupabaseAdmin();

    // Mark as cancelled rather than hard delete
    const { data: shift, error } = await supabase
      .from('open_shifts')
      .update({ is_cancelled: true })
      .eq('id', id)
      .select(`
        *,
        signups:shift_signups(
          instructor:instructor_id(id, name, email)
        )
      `)
      .single();

    if (error) throw error;

    // Fire-and-forget: cancel all Google Calendar events for this shift
    try {
      const { cancelShiftEvents } = await import('@/lib/google-calendar');
      cancelShiftEvents(id).catch(() => {});
    } catch {
      // Calendar sync is best-effort
    }

    // Notify all signed-up instructors that the shift is cancelled (fire-and-forget)
    if (shift?.signups && shift.signups.length > 0) {
      const notifications = shift.signups
        .map((s: { instructor: { id: string; name: string; email: string } | { id: string; name: string; email: string }[] | null }) => {
          const instr = Array.isArray(s.instructor) ? s.instructor[0] : s.instructor;
          return instr?.email ? {
            userEmail: instr.email,
            type: 'shift_confirmed' as const,
            title: 'Shift cancelled',
            message: `The shift "${shift.title || 'Untitled'}" has been cancelled by ${currentUser.name || 'an admin'}.`,
            linkUrl: `/scheduling/shifts`,
            referenceType: 'open_shift',
            referenceId: id,
          } : null;
        })
        .filter(Boolean) as Parameters<typeof createBulkNotifications>[0];

      if (notifications.length > 0) {
        createBulkNotifications(notifications).catch(() => {});
      }
    }

    return NextResponse.json({ success: true, shift });
  } catch (error) {
    console.error('Error cancelling shift:', error);
    return NextResponse.json({ success: false, error: 'Failed to cancel shift' }, { status: 500 });
  }
}
